import React from 'react';
import './Safety.css';

const Safety = () => (
  <section className="safety" id="safety">
    <h2>Safety & Policies</h2>
    <ul>
      <li><strong>Cancellation Policy:</strong> 24-hour notice required for cancellations or rescheduling.</li>
      <li><strong>Safety Measures:</strong> Dual-control vehicles, regular sanitization, and adherence to all road safety rules.</li>
      <li><strong>Instructor Qualifications:</strong> All instructors are certified and background-checked.</li>
    </ul>
  </section>
);

export default Safety;
